import java.io.*;

public class CommandInjectionFixed {
    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));

        System.out.print("Enter a directory name: ");
        String directory = br.readLine();

        // Validate user input to prevent command injection
        if (!directory.matches("[a-zA-Z0-9_/]+")) {
            System.out.println("Invalid directory name");
            return;
        }

        ProcessBuilder processBuilder = new ProcessBuilder("ls", directory);

        Process process = processBuilder.start();

        BufferedReader reader = new BufferedReader(new InputStreamReader(process.getInputStream()));
        String line;

        while ((line = reader.readLine()) != null) {
            System.out.println(line);
        }
    }
}

